+
+    let states = [
+        ActorState::Created,
+        ActorState::Running,
+        ActorState::Stopping,
+        ActorState::Stopped,
+    ];
+
+    // All states should be distinct from each other
+    for (i, a) in states.iter().enumerate() {
+        for (j, b) in states.iter().enumerate() {
+            if i == j {
+                let eq = a == b;
+                assert_with_log!(eq, "same state should equal itself", true, eq);
+            } else {
+                let neq = a != b;
+                assert_with_log!(
