+    ($name:expr) => {
+        tracing::info!(test = $name, "=== TEST START ===");
+    };
+}
+
+/// Assertion with logging for better test output.
+#[macro_export]
+macro_rules! assert_with_log {
+    ($cond:expr, $msg:expr, $expected:expr, $actual:expr) => {
+        if !$cond {
+            tracing::error!(
+                message = $msg,
+                expected = ?$expected,
+                actual = ?$actual,
+                "Assertion failed"
+            );
+        }
+        assert!($cond, "{}: expected {:?}, got {:?}", $msg, $expected, $actual);
+    };
+}
